import json
import re
import numpy as np
import pandas as pd
import matplotlib.pyplot as plt


def _parse_step(v):
    # "1/1619" -> 1
    if isinstance(v, (int, float)):
        return int(v)
    if isinstance(v, str):
        m = re.match(r"^\s*(\d+)\s*/\s*(\d+)\s*$", v)
        if m:
            return int(m.group(1))
        try:
            return float(v)
        except Exception:
            return np.nan
    return np.nan


def _parse_percent(v):
    # "0.06%" -> 0.06
    if isinstance(v, (int, float)):
        return float(v)
    if isinstance(v, str):
        s = v.strip().replace("%", "")
        try:
            return float(s)
        except Exception:
            return np.nan
    return np.nan


def load_logging_jsonl(path: str) -> pd.DataFrame:
    rows = []
    with open(path, "r", encoding="utf-8") as f:
        for line in f:
            line = line.strip()
            if line:
                rows.append(json.loads(line))
    df = pd.DataFrame(rows)

    # x-axis: global_step
    if "global_step/max_steps" in df.columns:
        df["global_step"] = df["global_step/max_steps"].apply(_parse_step)
    elif "global_step" not in df.columns:
        df["global_step"] = np.arange(len(df))

    # percentage to numeric
    if "percentage" in df.columns:
        df["percentage_num"] = df["percentage"].apply(_parse_percent)

    # try convert columns to numeric when possible
    for c in df.columns:
        if c in ("elapsed_time", "remaining_time", "global_step/max_steps", "percentage"):
            continue
        df[c] = pd.to_numeric(df[c], errors="ignore")

    df = df.sort_values("global_step").reset_index(drop=True)
    return df


def plot_main_metrics(df: pd.DataFrame, smooth_window: int = 0, figsize=(14, 14)):
    """
    smooth_window: 移动平均窗口，0 表示不平滑
    """
    def smooth(y):
        if smooth_window and smooth_window > 1 and len(y) >= smooth_window:
            return pd.Series(y).rolling(smooth_window, min_periods=1).mean().values
        return y

    x = df["global_step"].values

    groups = [
        ("loss / kl", ["loss", "kl"]),
        ("reward", ["reward", "reward_std", "frac_reward_zero_std"]),
        ("grad_norm & learning_rate", ["grad_norm", "learning_rate"]),
        ("completion length", ["completions/mean_length", "completions/min_length", "completions/max_length"]),
        ("clipped_ratio", ["completions/clipped_ratio"]),
        ("reward components (mean)", ["rewards/MultiModalAccuracyORM/mean", "rewards/Format/mean"]),
        ("reward components (std)", ["rewards/MultiModalAccuracyORM/std", "rewards/Format/std"]),
        ("speed & memory", ["train_speed(iter/s)", "memory(GiB)"]),
    ]

    # 只画存在的指标
    existing = [(title, [c for c in cols if c in df.columns]) for title, cols in groups]
    existing = [(t, cs) for t, cs in existing if len(cs) > 0]
    n = len(existing)
    if n == 0:
        raise ValueError("DataFrame 里找不到可画的主要指标列。")

    ncols = 2
    nrows = int(np.ceil(n / ncols))
    fig, axes = plt.subplots(nrows, ncols, figsize=figsize, dpi=150)
    axes = np.array(axes).reshape(-1)

    i = 0
    for title, cols in existing:
        ax = axes[i]; i += 1
        for c in cols:
            y = df[c].values
            if not np.issubdtype(pd.Series(y).dtype, np.number):
                continue
            ax.plot(x, smooth(y), label=c)
        ax.set_title(title)
        ax.set_xlabel("global_step")
        ax.grid(True, alpha=0.3)
        ax.legend(fontsize=8, loc="best")

    for j in range(i, len(axes)):
        axes[j].axis("off")

    fig.tight_layout()
    return fig


# ====== 直接在这里改路径并运行即可（不需要命令行） ======
path = "logging.jsonl"      # 改成你的文件路径
out_img = "metrics.png"     # 输出图片文件名
smooth_window = 20          # 0=不平滑；可改成 10/20/50 等

df = load_logging_jsonl(path)
fig = plot_main_metrics(df, smooth_window=smooth_window, figsize=(14, 14))
fig.savefig(out_img, bbox_inches="tight")
plt.show()
```

你这报错的根因是：`global_step/max_steps` 这一列里有缺失值（NaN），而 `_parse_step` 里对 `(int, float)` 直接 `int(v)`，遇到 `np.nan` 就会触发 `ValueError: cannot convert float NaN to integer`。

把 `_parse_step` 改成先判断 NaN，再转 int；同时 `global_step` 建议用 `pd.to_numeric(..., errors="coerce")` 后再补齐（用行号或 forward-fill）。

下面给你一份“直接可替换”的完整脚本（无命令行），对 NaN/缺字段更鲁棒：

```python
import json
import re
import numpy as np
import pandas as pd
import matplotlib.pyplot as plt


def _is_nan(x):
    try:
        return pd.isna(x)
    except Exception:
        return False


def _parse_step(v):
    """Parse step from values like '1/1619' or numeric. Return float (can be NaN)."""
    if _is_nan(v):
        return np.nan

    if isinstance(v, (int, np.integer)):
        return float(v)

    if isinstance(v, (float, np.floating)):
        # normal float
        return float(v)

    if isinstance(v, str):
        s = v.strip()
        m = re.match(r"^\s*(\d+)\s*/\s*(\d+)\s*$", s)
        if m:
            return float(m.group(1))
        # fallback: try parse number
        try:
            return float(s)
        except Exception:
            return np.nan

    return np.nan


def _parse_percent(v):
    if _is_nan(v):
        return np.nan
    if isinstance(v, (int, float, np.integer, np.floating)):
        return float(v)
    if isinstance(v, str):
        s = v.strip().replace("%", "")
        try:
            return float(s)
        except Exception:
            return np.nan
    return np.nan


def load_logging_jsonl(path: str) -> pd.DataFrame:
    rows = []
    with open(path, "r", encoding="utf-8") as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            try:
                rows.append(json.loads(line))
            except json.JSONDecodeError:
                # 跳过坏行
                continue

    df = pd.DataFrame(rows)

    # build global_step robustly
    if "global_step/max_steps" in df.columns:
        step = df["global_step/max_steps"].apply(_parse_step)
        step = pd.to_numeric(step, errors="coerce")

        # 如果有缺失：先尝试 forward-fill；开头还是缺失就用行号补
        step = step.ffill()
        if step.isna().any():
            step = step.fillna(pd.Series(np.arange(len(step)), index=step.index))

        df["global_step"] = step.astype(int)
    elif "global_step" in df.columns:
        step = pd.to_numeric(df["global_step"], errors="coerce").ffill()
        if step.isna().any():
            step = step.fillna(pd.Series(np.arange(len(step)), index=step.index))
        df["global_step"] = step.astype(int)
    else:
        df["global_step"] = np.arange(len(df))

    # percentage
    if "percentage" in df.columns:
        df["percentage_num"] = df["percentage"].apply(_parse_percent)

    # numeric coercion for other columns (尽量转成数值，转不了保留原样)
    for c in df.columns:
        if c in ("elapsed_time", "remaining_time", "global_step/max_steps", "percentage"):
            continue
        df[c] = pd.to_numeric(df[c], errors="ignore")

    df = df.sort_values("global_step").reset_index(drop=True)
    return df


def plot_main_metrics(df: pd.DataFrame, smooth_window: int = 0, figsize=(14, 14)):
    def smooth(y):
        y = pd.to_numeric(pd.Series(y), errors="coerce")
        if smooth_window and smooth_window > 1:
            return y.rolling(smooth_window, min_periods=1).mean().to_numpy()
        return y.to_numpy()

    x = df["global_step"].to_numpy()

    groups = [
        ("loss / kl", ["loss", "kl"]),
        ("reward", ["reward", "reward_std", "frac_reward_zero_std"]),
        ("grad_norm & learning_rate", ["grad_norm", "learning_rate"]),
        ("completion length", ["completions/mean_length", "completions/min_length", "completions/max_length"]),
        ("clipped_ratio", ["completions/clipped_ratio"]),
        ("reward components (mean)", ["rewards/MultiModalAccuracyORM/mean", "rewards/Format/mean"]),
        ("reward components (std)", ["rewards/MultiModalAccuracyORM/std", "rewards/Format/std"]),
        ("speed & memory", ["train_speed(iter/s)", "memory(GiB)"]),
    ]

    existing = []
    for title, cols in groups:
        cols_exist = [c for c in cols if c in df.columns]
        if cols_exist:
            existing.append((title, cols_exist))

    if not existing:
        raise ValueError("DataFrame 里找不到可画的主要指标列。")

    n = len(existing)
    ncols = 2
    nrows = int(np.ceil(n / ncols))
    fig, axes = plt.subplots(nrows, ncols, figsize=figsize, dpi=150)
    axes = np.array(axes).reshape(-1)

    i = 0
    for title, cols in existing:
        ax = axes[i]; i += 1
        for c in cols:
            y = pd.to_numeric(df[c], errors="coerce")
            if y.notna().sum() == 0:
                continue
            ax.plot(x, smooth(y), label=c)
        ax.set_title(title)
        ax.set_xlabel("global_step")
        ax.grid(True, alpha=0.3)
        ax.legend(fontsize=8, loc="best")

    for j in range(i, len(axes)):
        axes[j].axis("off")

    fig.tight_layout()
    return fig


# ====== 直接改这里的路径运行即可 ======
path = "logging.jsonl"      # 改成你的 logging.jsonl 路径
out_img = "metrics.png"     # 输出图片名
smooth_window = 20          # 0=不平滑

df = load_logging_jsonl(path)
fig = plot_main_metrics(df, smooth_window=smooth_window, figsize=(14, 14))
fig.savefig(out_img, bbox_inches="tight")
plt.show()
```

